def eval_uncertainty_calibration(
    reasoning_text: str,
    context_provided: str,
) -> dict:
    """
    Score 0.0-1.0 whether the agent is appropriately calibrated.
    Also returns a flag if hallucinated confidence is detected.
    """
    import json, re
    prompt = (
        f"Context provided to agent: {context_provided}\n\n"
        f"Agent reasoning: {reasoning_text}\n\n"
        "Evaluate calibration:\n"
        "1. Does the agent express appropriate uncertainty about things "
        "not in the context?\n"
        "2. Does it avoid asserting facts not supported by the context?\n"
        "3. calibration_score 0.0-1.0\n"
        "4. hallucinated_confidence: true/false (asserts facts with no basis)\n"
        'Return JSON: {"calibration_score": 0.0, "hallucinated_confidence": false}'
    )
    msg = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=80,
        messages=[{"role": "user", "content": prompt}],
    )
    m = re.search(r'\{[^}]+\}', msg.content[0].text)
    if not m:
        return {"calibration_score": 0.0, "hallucinated_confidence": True}
    try:
        return json.loads(m.group())
    except json.JSONDecodeError:
        return {"calibration_score": 0.0, "hallucinated_confidence": True}

import anthropic

aclient = anthropic.Anthropic()

def run_with_thinking_eval(
    system: str,
    user_input: str,
    budget_tokens: int = 5000,
) -> dict:
    """Run a request with extended thinking and evaluate the reasoning."""
    response = aclient.messages.create(
        model="claude-opus-4-8",
        max_tokens=8000,
        thinking={"type": "enabled", "budget_tokens": budget_tokens},
        system=system,
        messages=[{"role": "user", "content": user_input}],
    )

    thinking_text = ""
    response_text = ""
    for block in response.content:
        if block.type == "thinking":
            thinking_text = block.thinking
        elif block.type == "text":
            response_text = block.text

    if not thinking_text:
        return {"thinking": "", "response": response_text, "reasoning_score": None}

    constraint_score = eval_constraint_identification(user_input, thinking_text)
    calibration = eval_uncertainty_calibration(thinking_text, system + user_input)

    return {
        "thinking": thinking_text,
        "response": response_text,
        "constraint_score": constraint_score,
        "calibration_score": calibration["calibration_score"],
        "hallucinated_confidence": calibration["hallucinated_confidence"],
    }

def check_constraint_coverage(
    reasoning_text: str,
    required_constraints: list[str],
) -> dict:
    """
    Check whether the reasoning text addresses each required constraint.
    Returns per-constraint coverage and overall coverage rate.
    """
    from anthropic import Anthropic
    client = Anthropic()
    import json

    prompt = (
        f"Reasoning text:\n{reasoning_text}\n\n"
        f"Required constraints to identify: {required_constraints}\n\n"
        "For each constraint, did the reasoning text address it? "
        'Return JSON: {"coverage": {"constraint_text": true/false, ...}}'
    )
    msg = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=256,
        messages=[{"role": "user", "content": prompt}],
    )
    import re
    m = re.search(r'\{.*\}', msg.content[0].text, re.DOTALL)
    if not m:
        return {"coverage": {}, "coverage_rate": 0.0}
    try:
        result = json.loads(m.group())
        coverage = result.get("coverage", {})
        rate = sum(coverage.values()) / len(coverage) if coverage else 0.0
        return {"coverage": coverage, "coverage_rate": rate}
    except (json.JSONDecodeError, ZeroDivisionError):
        return {"coverage": {}, "coverage_rate": 0.0}
